function escapeHTML(e){if(!e)return"";const t=document.createElement("div");return t.textContent=e,t.innerHTML}function createTextElement(e,t,n=""){const c=document.createElement(e);return c.textContent=t||"",n&&(c.className=n),c}function setTrustedHTML(e,t){e.innerHTML=t}function replaceChildren(e,t){e.textContent="",t.forEach(t=>e.appendChild(t))}